// ===== UPWORK JOB FILTER & DEDUPLICATOR =====
const keywords = ['laravel', 'php', 'api', 'payment', 'bug fix', 'bug fixing', 'rest api', 'mysql'];
const blacklist = ['wordpress', 'shopify', 'wix', '.net', 'react native', 'flutter', 'django'];

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenJobs) staticData.seenJobs = {};

const now = Date.now();
// Clean entries older than 7 days
for (const [id, ts] of Object.entries(staticData.seenJobs)) {
  if (now - ts > 7 * 24 * 60 * 60 * 1000) delete staticData.seenJobs[id];
}

const results = [];
for (const item of $input.all()) {
  const title = (item.json.title || '').toLowerCase();
  const desc = (item.json.contentSnippet || item.json.content || item.json.description || '').toLowerCase();
  const link = item.json.link || item.json.guid || '';
  const combined = title + ' ' + desc;
  const jobId = link || title;

  if (staticData.seenJobs[jobId]) continue;

  const matched = keywords.filter(kw => combined.includes(kw));
  if (matched.length === 0) continue;

  const blocked = blacklist.some(kw => combined.includes(kw));
  if (blocked) continue;

  const isVerified = combined.includes('payment verified') || combined.includes('payment method verified');
  const score = (isVerified ? 2 : 0) + matched.length;

  staticData.seenJobs[jobId] = now;

  const sysPrompt = 'You are an expert PHP/Laravel developer (8+ yrs). Specialties: Laravel apps, payment integrations, REST APIs, MySQL, PHP debugging. Write a compelling Upwork proposal (150-250 words). Rules: 1) Hook showing you understand THEIR problem 2) 2-3 relevant experiences 3) 3-4 bullet approach 4) Timeline estimate 5) Confident closing 6) Sound human NOT generic 7) NEVER say Dear Hiring Manager 8) First person, direct, confident';
  const userPrompt = 'JOB TITLE: ' + (item.json.title || 'N/A') + '\n\nDESCRIPTION:\n' + (item.json.contentSnippet || item.json.content || item.json.description || 'N/A') + '\n\nWrite the proposal now:';

  results.push({
    json: {
      title: item.json.title || 'No Title',
      link: link,
      description: item.json.contentSnippet || item.json.content || item.json.description || '',
      pubDate: item.json.pubDate || item.json.isoDate || '',
      isPaymentVerified: isVerified,
      matchedKeywords: matched,
      qualityScore: score,
      openaiBody: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: sysPrompt },
          { role: 'user', content: userPrompt }
        ],
        temperature: 0.7,
        max_tokens: 600
      })
    }
  });
}

results.sort((a, b) => b.json.qualityScore - a.json.qualityScore);
return results.length > 0 ? results : [{ json: { noResults: true, title: '' } }];

const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  const proposal = items[i].json.choices?.[0]?.message?.content || 'Failed to generate proposal';
  const job = $('Filter and Prepare').all()[i]?.json || {};
  const title = job.title || 'Unknown Job';
  const link = job.link || '#';
  const isVerified = job.isPaymentVerified || false;
  const matched = (job.matchedKeywords || []).join(', ');

  const subject = '🚀 New Upwork Job: ' + title;
  const body = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><div style="background:linear-gradient(135deg,#667eea,#764ba2);padding:20px;border-radius:12px 12px 0 0;text-align:center"><h1 style="color:#fff;margin:0;font-size:22px">🎯 New Upwork Job Match!</h1></div><div style="background:#f8f9fa;padding:20px;border:1px solid #e9ecef"><h2 style="color:#2d3748;margin-top:0">' + title + '</h2>' + (isVerified ? '<span style="background:#48bb78;color:#fff;padding:3px 10px;border-radius:20px;font-size:12px">✅ Payment Verified</span>' : '<span style="background:#ed8936;color:#fff;padding:3px 10px;border-radius:20px;font-size:12px">⚠️ Not Verified</span>') + '<p style="margin-top:10px"><strong>Matched Skills:</strong> ' + matched + '</p><div style="margin:15px 0"><a href="' + link + '" style="display:inline-block;background:#4299e1;color:#fff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:bold">🔗 View Job on Upwork</a></div></div><div style="background:#fff;padding:20px;border:1px solid #e9ecef;border-top:none"><h3 style="color:#2d3748;border-bottom:2px solid #667eea;padding-bottom:8px">📝 AI-Generated Proposal</h3><div style="background:#f7fafc;padding:15px;border-radius:8px;border-left:4px solid #667eea;white-space:pre-wrap;line-height:1.6">' + proposal + '</div></div><div style="background:#2d3748;color:#a0aec0;padding:15px;border-radius:0 0 12px 12px;text-align:center;font-size:12px"><p>Upwork Auto Job Hunter • n8n</p></div></div>';

  results.push({ json: { subject, body, title, link, proposal } });
}
return results;
